export function VedaLogo({ className, size = 28, height = 40, variant = "mark" }: VedaLogoProps) {
  const id = useId().replace(/:/g, "");
  const markGradientId = `${id}-mark-grad`;
  const bgGradientId = `${id}-bg-grad`;
  const filterId = `${id}-filter`;

  if (variant === "full") {
    return (
      <VedaLogoFull
        className={className}
        height={height}
        bgGradientId={bgGradientId}
        markGradientId={markGradientId}
        filterId={filterId}
      />
    );
  }

  return (
    <VedaLogoMark
      className={className}
      size={size}
      bgGradientId={bgGradientId}
      markGradientId={markGradientId}
      filterId={filterId}
    />
  );
}
